staticData.drafts[newDraftId] = { ...d.draft, tweet, stage: 'tweet_review', createdAt: new Date().toISOString() };
return [{ json: { ...d.draft, draftId: newDraftId, tweet } }];

const d = $input.first().json;
const cancellableStages = ['blog_review', 'linkedin_review', 'tweet_review', 'medium_published', 'linkedin_published'];
if (!d.draft) return [{ json: { error: 'Draft not found.', draftId: d.draftId } }];
if (!cancellableStages.includes(d.draft.stage)) return [{ json: { error: `Cannot cancel: draft is already '${d.draft.stage}'.`, draftId: d.draftId } }];
return [{ json: { ok: true, ...d } }];

const d = $input.first().json;
const staticData = $getWorkflowStaticData('global');
staticData.drafts[d.draftId] = { ...d.draft, stage: 'cancelled', updatedAt: new Date().toISOString() };
return [{ json: d }];

const d = $input.first().json;
const platform = d.platform;
const confirmed = d.confirmed === 'true' || d.confirmed === true;
const expectedStage = { medium: 'publishing_medium', linkedin: 'publishing_linkedin', twitter: 'publishing_tweet' }[platform];
if (!d.draft) return [{ json: { error: 'Draft not found.', draftId: d.draftId } }];
if (!expectedStage) return [{ json: { error: `Unknown platform: ${platform}`, draftId: d.draftId } }];
if (d.draft.stage !== expectedStage) return [{ json: { error: `Cannot confirm publish for ${platform}: draft is at stage '${d.draft.stage}'.`, draftId: d.draftId } }];
return [{ json: { ok: true, platform, confirmed, ...d } }];

const d = $input.first().json;
const staticData = $getWorkflowStaticData('global');
if (d.confirmed) {
  if (d.platform === 'medium') {
    const mediumUrl = d.mediumUrlInput || '';
    staticData.drafts[d.draftId] = { ...d.draft, mediumUrl, stage: 'medium_published', updatedAt: new Date().toISOString() };
    return [{ json: { ...d, mediumUrl, nextAction: 'linkedin_gen' } }];
  } else if (d.platform === 'linkedin') {
    staticData.drafts[d.draftId] = { ...d.draft, stage: 'linkedin_published', updatedAt: new Date().toISOString() };
    return [{ json: { ...d, nextAction: 'tweet_gen' } }];
  } else if (d.platform === 'twitter') {
    staticData.drafts[d.draftId] = { ...d.draft, stage: 'completed', updatedAt: new Date().toISOString() };
    return [{ json: { ...d, nextAction: 'done' } }];
  }
} else {
  if (d.platform === 'medium') {
    staticData.drafts[d.draftId] = { ...d.draft, stage: 'blog_review', updatedAt: new Date().toISOString() };
    return [{ json: { ...d, nextAction: 'blog_review' } }];
  } else if (d.platform === 'linkedin') {
    staticData.drafts[d.draftId] = { ...d.draft, stage: 'linkedin_review', updatedAt: new Date().toISOString() };
    return [{ json: { ...d, nextAction: 'linkedin_review' } }];
  } else if (d.platform === 'twitter') {
    staticData.drafts[d.draftId] = { ...d.draft, stage: 'tweet_review', updatedAt: new Date().toISOString() };
    return [{ json: { ...d, nextAction: 'tweet_review' } }];
  }
}
return [{ json: d }];
